import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

function OfferLetter() {
  const { applicationId } = useParams();
  const navigate = useNavigate();

  const [application, setApplication] = useState(null);
  const [salary, setSalary] = useState("");
  const [joiningDate, setJoiningDate] = useState("");
  const [location, setLocation] = useState("");
  const [notes, setNotes] = useState("");

  /* LOAD APPLICATION */
  useEffect(() => {
    const apps =
      JSON.parse(localStorage.getItem("applications")) || [];

    const found = apps.find(
      (a) => String(a.id) === String(applicationId)
    );

    setApplication(found);
  }, [applicationId]);

  /* LOAD EXISTING OFFER (EDIT MODE) */
  useEffect(() => {
    const offers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const existing = offers.find(
      (o) => String(o.applicationId) === String(applicationId)
    );

    if (existing) {
      setSalary(existing.salary);
      setJoiningDate(existing.joiningDate);
      setLocation(existing.location);
      setNotes(existing.notes || "");
    }
  }, [applicationId]);

  /* SAVE OFFER */
  const handleSaveOffer = () => {
    if (!salary || !joiningDate || !location) {
      alert("Fill all required fields");
      return;
    }

    // Save offer
    const offers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const updatedOffers = offers.filter(
      (o) => String(o.applicationId) !== String(applicationId)
    );

    updatedOffers.push({
      applicationId,
      email: application.email,
      jobTitle: application.jobTitle,
      salary,
      joiningDate,
      offerDate: new Date().toISOString().split("T")[0],
      location,
      notes,
    });

    localStorage.setItem(
      "offerLetters",
      JSON.stringify(updatedOffers)
    );

    // Update application status
    const apps =
      JSON.parse(localStorage.getItem("applications")) || [];

    const updatedApps = apps.map((a) =>
      String(a.id) === String(applicationId)
        ? { ...a, status: "Offer Sent" }
        : a
    );

    localStorage.setItem(
      "applications",
      JSON.stringify(updatedApps)
    );

    alert("Offer saved successfully");

    // 🔥 FORCE UI RELOAD
    navigate("/dashboard/view-applicants", { replace: true });
    window.location.reload();
  };

  if (!application) return <p>Loading...</p>;

  return (
    <div style={{ marginTop: "25px", maxWidth: "600px" }}>
      <h2>Generate Offer Letter</h2>

      <p><b>Name:</b> {application.employeeName}</p>
      <p><b>Email:</b> {application.email}</p>
      <p><b>Job Title:</b> {application.jobTitle}</p>

      <input
        type="number"
        placeholder="Annual Salary"
        value={salary}
        onChange={(e) => setSalary(e.target.value)}
      />

      <label>Date of Joining</label>
      <input
        type="date"
        value={joiningDate}
        onChange={(e) => setJoiningDate(e.target.value)}
      />

      <input
        type="text"
        placeholder="Work Location"
        value={location}
        onChange={(e) => setLocation(e.target.value)}
      />

      <textarea
        placeholder="Notes (optional)"
        value={notes}
        onChange={(e) => setNotes(e.target.value)}
      />

      <button onClick={handleSaveOffer}>
        Save Offer Letter
      </button>
    </div>
  );
}

export default OfferLetter;
